def validate(args, output):
    grid = args[0]
    m = len(grid)
    n = len(grid[0]) if m else 0
    if not isinstance(output, list):
        return False
    if any(not isinstance(x, int) or isinstance(x, bool) for x in output):
        return False
    k = len(output)
    if len(set(output)) != k:
        return False
    if output != sorted(output):
        return False
    for idx in output:
        if idx < 0 or idx >= m:
            return False
    if k == 0:
        # A good subset exists at all iff some row is all-zero, or some pair
        # of rows has disjoint 1-bits (columns never both 1). This reduction
        # is valid because n <= 5, so patterns are cheap to enumerate; if
        # either condition holds, an empty answer is wrong.
        patterns = set()
        for row in grid:
            p = 0
            for j in range(n):
                if row[j]:
                    p |= (1 << j)
            patterns.add(p)
        if 0 in patterns:
            return False
        plist = sorted(patterns)
        for a in range(len(plist)):
            for b in range(a + 1, len(plist)):
                if plist[a] & plist[b] == 0:
                    return False
        return True
    limit = k // 2
    for j in range(n):
        total = sum(grid[i][j] for i in output)
        if total > limit:
            return False
    return True

