function validate(args, output) {
    const grid = args[0];
    const m = grid.length;
    const n = m ? grid[0].length : 0;
    if (!Array.isArray(output)) return false;
    for (const x of output) {
        if (!Number.isInteger(x)) return false;
    }
    const k = output.length;
    if (new Set(output).size !== k) return false;
    for (let i = 1; i < k; i++) {
        if (output[i] < output[i - 1]) return false;
    }
    for (const idx of output) {
        if (idx < 0 || idx >= m) return false;
    }
    if (k === 0) {
        const patterns = new Set();
        for (const row of grid) {
            let p = 0;
            for (let j = 0; j < n; j++) {
                if (row[j]) p |= (1 << j);
            }
            patterns.add(p);
        }
        if (patterns.has(0)) return false;
        const plist = Array.from(patterns).sort((a, b) => a - b);
        for (let a = 0; a < plist.length; a++) {
            for (let b = a + 1; b < plist.length; b++) {
                if ((plist[a] & plist[b]) === 0) return false;
            }
        }
        return true;
    }
    const limit = Math.floor(k / 2);
    for (let j = 0; j < n; j++) {
        let total = 0;
        for (const i of output) total += grid[i][j];
        if (total > limit) return false;
    }
    return true;
}

