import itertools


class Solution:
    def goodSubsetofBinaryMatrix(self, grid):
        m = len(grid)
        n = len(grid[0]) if m else 0

        def pattern(row):
            p = 0
            for j in range(n):
                if row[j]:
                    p |= (1 << j)
            return p

        first_idx = {}
        zero_idx = None
        for i, row in enumerate(grid):
            p = pattern(row)
            if p == 0 and zero_idx is None:
                zero_idx = i
            if p not in first_idx:
                first_idx[p] = i
        if zero_idx is not None:
            return [zero_idx]

        def column_sums_ok(rows):
            k = len(rows)
            limit = k // 2
            for j in range(n):
                total = sum(grid[r][j] for r in rows)
                if total > limit:
                    return False
            return True

        distinct = sorted(first_idx.keys())
        for p1, p2 in itertools.combinations(distinct, 2):
            rows = [first_idx[p1], first_idx[p2]]
            if column_sums_ok(rows):
                return sorted(rows)
        return []

