class Solution:
    def goodSubsetofBinaryMatrix(self, grid: List[List[int]]) -> List[int]:
        m = len(grid)
        n = len(grid[0]) if m else 0
        first_index = {}
        zero_idx = None
        for i, row in enumerate(grid):
            p = 0
            for j in range(n):
                if row[j]:
                    p |= (1 << j)
            if p == 0 and zero_idx is None:
                zero_idx = i
            if p not in first_index:
                first_index[p] = i
        if zero_idx is not None:
            return [zero_idx]
        patterns_list = sorted(first_index.keys())
        for a in range(len(patterns_list)):
            for b in range(a + 1, len(patterns_list)):
                p1 = patterns_list[a]
                p2 = patterns_list[b]
                if p1 & p2 == 0:
                    i1 = first_index[p1]
                    i2 = first_index[p2]
                    return sorted([i1, i2])
        return []

