var goodSubsetofBinaryMatrix = function(grid) {
    const m = grid.length;
    const n = m ? grid[0].length : 0;
    const firstIndex = new Map();
    let zeroIdx = -1;
    for (let i = 0; i < m; i++) {
        let p = 0;
        for (let j = 0; j < n; j++) {
            if (grid[i][j]) p |= (1 << j);
        }
        if (p === 0 && zeroIdx === -1) zeroIdx = i;
        if (!firstIndex.has(p)) firstIndex.set(p, i);
    }
    if (zeroIdx !== -1) return [zeroIdx];
    const patterns = Array.from(firstIndex.keys()).sort((a, b) => a - b);
    for (let a = 0; a < patterns.length; a++) {
        for (let b = a + 1; b < patterns.length; b++) {
            const p1 = patterns[a], p2 = patterns[b];
            if ((p1 & p2) === 0) {
                const i1 = firstIndex.get(p1);
                const i2 = firstIndex.get(p2);
                return i1 < i2 ? [i1, i2] : [i2, i1];
            }
        }
    }
    return [];
};
